typedef struct alignas(64) HazardThreadSlot {
// 16 bytes
_Atomic uintptr_t slots[2];
// 1 byte
_Atomic bool active;
// 47 bytes padding
char _pad[64 - sizeof(_Atomic uintptr_t)*2 - sizeof(_Atomic bool)];
} HazardThreadSlot;

// Static validation of memory layout
_Static_assert(sizeof(HazardThreadSlot) == 64,
"Alignment error: False sharing possible");
